solutions.python:
import json

class Solution:
  def filterDocument(self, document, projection):
    if isinstance(projection, dict):
      for key in projection:
        if key in document:
          if isinstance(document[key], dict):
            document[key] = self.filterDocument(document[key], projection[key])
          elif document[key] is not None:
            document[key] = projection[key]
      return document
    return document

def main():
  s = Solution()
  document = json.loads(input())
  projection = json.loads(input())
  print(json.dumps(s.filterDocument(document, projection)))

if __name__ == '__main__':
  main()
